messages.content:
CLUSTER:
[
 {
  "riskId": "risk.boundary-substitution.enterprise-gpu-pods-skip-pdus",
  "title": "The only growing part of the enterprise 29% ships as pre-integrated GPU racks with shelf power — the venture addresses only the shrinking remainder",
  "narrative": "seg.enterprise (0.29) looks like the conservative, PDU-sticky base: on-prem halls refreshing rack power on slow cycles. But Synergy is explicit that enterprise capacity was flat for years and is only now growing again 'thanks to GenAI applications and GPU infrastructure' — and that increment arrives as OEM-integrated GPU pods built to vendor reference designs with in-rack power shelves, not as field-installed PDUs. Meanwhile the legacy stock the PDU thesis actually addresses is the part Synergy shows declining two percentage points a year toward 19% by 2031. The model books the whole 0.29 as PDU-addressable; structurally, only the shrinking half is.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Synergy: after a sustained period of no growth, on-premise capacity is getting a boost from GenAI/GPU infrastructure — the enterprise segment's growth is exclusively AI-density capacity",
    "refs": [
     "digest:seg-mix#c20",
     "digest:seg-mix#c2"
    ]
   },
   {
    "step": "propagation",
    "text": "Enterprise AI capacity is procured as pre-integrated racks (vendor reference designs with busbar/power-shelf distribution) from OEMs, bypassing the discrete rack-PDU purchase entirely; the residual PDU-buying legacy stock is the component falling ~2pp/year toward 19% share by 2031",
    "refs": [
     "digest:seg-mix#c22",
     "digest:seg-mix#c5"
    ]
   },
   {
    "step": "model-impact",
    "text": "seg.enterprise 0.29 is a single-source capacity share with no sensitivityRange and no decomposition into legacy-refresh vs GPU-pod capacity; treating all of it as PDU-addressable overstates the enterprise slice a new PDU entrant can sell into during Year 1",
    "refs": [
     "ledger:seg.enterprise",
     "digest:seg-mix#c3"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Form factor of enterprise AI infrastructure orders (integrated rack-scale systems vs component builds)",
    "where": "Dell/HPE/Lenovo quarterly earnings — AI server segment commentary on rack-scale vs unit shipments; NVIDIA reference-design partner announcements",
    "threshold": "Rack-scale integrated systems exceeding ~50% of enterprise AI infrastructure revenue mix",
    "updates": "increases"
   },
   {
    "signal": "PDU attach rate in CE enterprise channel sell-through",
    "where": "CE IT distribution (also/ALSO, Ingram Micro) product-category reporting; Schneider/Vertiv earnings commentary on enterprise vs cloud PDU demand",
    "threshold": "Enterprise PDU line flat-to-down while enterprise AI server line grows double-digit",
    "updates": "increases"
   }
  ],
  "judgeTotal": 16
 },
 {
  "riskId": "risk.structure-independence.enterprise-share-is-stock-not-spend",
  "title": "Enterprise 0.29 is a capacity stock, not PDU spend: a declining, refresh-lagged slice inflates nearly a third of TAM",
  "narrative": "seg.enterprise carries 29% of the market because Synergy says enterprise on-prem holds 32% of global CAPACITY. But rack-PDU revenue follows flows — new builds and refresh — not standing stock. Enterprise on-prem is the one segment in structural decline (56% in 2018 → 32% now → 19% by 2031, minus two points a year): near-zero new-build demand, refresh cycles stretched as workloads migrate out, and the node's own provenance admits refresh demand 'may lag capacity share'. Meanwhile the geo axis never measured enterprise at all (colo denominator), so this slice is doubly unobserved. A third of the TAM is priced off the one number — stock share — that is least predictive of what an entrant can invoice.",
  "mechanism": [
   {
    "step": "trigger",
    "text": "Enterprise on-prem capacity share is in documented structural decline: 56% (2018) → 32% (end-2025) → 19% (2031), falling ~2pp per year",
    "refs": [
     "digest:seg-mix#c2",
     "digest:seg-mix#c5",
     "digest:seg-mix#c22"
    ]
   },
   {
    "step": "propagation",
    "text": "PDU purchases track capacity flows, not stock: a shrinking installed base generates minimal new-build PDU demand and deferred refresh, so spend share sits well below capacity share — a lag the node's own rationale flags but does not quantify; the GenAI on-prem boost is described only as relief 'after a sustained period of essentially no growth'",
    "refs": [
     "ledger:seg.enterprise",
     "digest:seg-mix#c20"
    ]
   },
   {
    "step": "model-impact",
    "text": "seg.enterprise 0.29 overstates the invoiceable enterprise slice of CE rack-PDU demand, and because the geo weights are colo-scoped this overstatement was never exposed to any country-level evidence — the funnel books phantom demand across every geo × enterprise cell",
    "refs": [
     "ledger:seg.enterprise",
     "digest:geo-region-denominator#c0"
    ]
   }
  ],
  "indicators": [
   {
    "signal": "Enterprise/on-prem share in successive Synergy vintages and any GenAI-driven on-prem build commentary",
    "where": "Synergy Research quarterly capacity-share releases; CRN coverage of the hyperscale-vs-enterprise split",
    "threshold": "On-prem share falling faster than 2pp/yr, or GenAI boost fading from the narrative",
    "updates": "increases"
   },
   {
    "signal": "Channel mix for rack power sold into enterprise vs DC operators",
    "where": "Schneider/Eaton/Vertiv earnings-call commentary and distributor (IT-VAR) rack-power sell-through reports",
    "threshold": "Enterprise/IT-channel rack-PDU revenue flat or declining YoY while operator segment grows double-digit",
    "updates": "increases"
   }
  ],
  "judgeTotal": 15
 }
]

Every riskId must appear in exactly one group (as keepId or inside absorbs).
Emit JSON: { rationale, groups: [{keepId, absorbs: [true-duplicate riskIds, [] if none], foldedIndicators: []}] }
